from google.cloud import storage, firestore, pubsub_v1
import os
import json
import base64
from datetime import datetime, timezone

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

OUTPUT_TOPIC = os.environ.get("OUTPUT_TOPIC", "")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")

def process_gcs_file(event, context):
    bucket_name = event["bucket"]
    file_name = event["name"]
    generation = event.get("generation")
    time_created = event.get("timeCreated")
    updated = event.get("updated")

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    content = blob.download_as_bytes()

    metadata = {
        "bucket": bucket_name,
        "name": file_name,
        "generation": generation,
        "size_bytes": len(content),
        "time_created": time_created,
        "updated": updated,
        "processed_at": datetime.now(timezone.utc).isoformat(),
    }

    doc_ref = firestore_client.collection(FIRESTORE_COLLECTION).document(
        f"{bucket_name}_{file_name.replace('/', '_')}_{generation or 'latest'}"
    )
    doc_ref.set(metadata, merge=True)

    if OUTPUT_TOPIC:
        topic_path = OUTPUT_TOPIC
        if not OUTPUT_TOPIC.startswith("projects/"):
            project_id = storage_client.project
            topic_path = publisher.topic_path(project_id, OUTPUT_TOPIC)

        message = {
            "event": "file_processed",
            "metadata": metadata,
            "content_base64": base64.b64encode(content).decode("utf-8"),
        }
        publisher.publish(topic_path, json.dumps(message).encode("utf-8"))

    return "OK"